175	    pub fn findAnchorsAndAliases(this: *Stringifier, global: *JSGlobalObject, value: JSValue, origin: ValueOrigin) StringifyError!void {
176	        if (!this.stack_check.isSafeToRecurse()) {
177	            return error.StackOverflow;
178	        }
179	
180	        const unwrapped = try value.unwrapBoxedPrimitive(global);
181	
182	        if (unwrapped.isNull()) {
183	            return;
184	        }
185	
186	        if (unwrapped.isNumber()) {
187	            return;
188	        }
189	
190	        if (unwrapped.isBigInt()) {
191	            return global.throw("YAML.stringify cannot serialize BigInt", .{});
192	        }
193	
194	        if (unwrapped.isBoolean()) {
195	            return;
196	        }
197	
198	        if (unwrapped.isString()) {
199	            return;
200	        }
201	
202	        if (comptime Environment.ci_assert) {
203	            bun.assertWithLocation(unwrapped.isObject(), @src());
204	        }
205	
206	        const object_entry = try this.known_collections.getOrPut(unwrapped);
207	        if (object_entry.found_existing) {
208	            // this will become an alias. increment counters here because
209	            // now the anchor/alias is confirmed used.
210	
211	            if (object_entry.value_ptr.used) {
212	                return;
213	            }
214	
215	            object_entry.value_ptr.used = true;
216	
217	            switch (object_entry.value_ptr.name) {
218	                .root => {
219	                    // only one possible
220	                },
221	                .array_item => |*counter| {
222	                    counter.* = this.array_item_counter;
223	                    this.array_item_counter += 1;
224	                },
225	                .prop_value => |*prop_value| {
226	                    const name_entry = try this.prop_names.getOrPut(prop_value.prop_name.byteSlice());
227	                    if (name_entry.found_existing) {
228	                        name_entry.value_ptr.* += 1;
229	                    } else {
230	                        name_entry.value_ptr.* = 0;
231	                    }
232	
233	                    prop_value.counter = name_entry.value_ptr.*;
234	                },
235	            }
236	            return;
237	        }
238	
239	        object_entry.value_ptr.* = .init(origin);
240	
241	        if (unwrapped.isArray()) {
242	            var iter = try unwrapped.arrayIterator(global);
243	            while (try iter.next()) |item| {
244	                if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
245	                    continue;
246	                }
247	
248	                try this.findAnchorsAndAliases(global, item, .array_item);
249	            }
250	            return;
251	        }
252	
253	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
254	            global,
255	            try unwrapped.toObject(global),
256	        );
257	        defer iter.deinit();
258	
259	        while (try iter.next()) |prop_name| {
260	            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
261	                continue;
262	            }
263	            try this.findAnchorsAndAliases(global, iter.value, .{ .prop_value = prop_name });
264	        }
265	    }
