556	                0x10 => this.builder.append(.latin1, "\\x10"),
557	                0x11 => this.builder.append(.latin1, "\\x11"),
558	                0x12 => this.builder.append(.latin1, "\\x12"),
559	                0x13 => this.builder.append(.latin1, "\\x13"),
560	                0x14 => this.builder.append(.latin1, "\\x14"),
561	                0x15 => this.builder.append(.latin1, "\\x15"),
562	                0x16 => this.builder.append(.latin1, "\\x16"),
563	                0x17 => this.builder.append(.latin1, "\\x17"),
564	                0x18 => this.builder.append(.latin1, "\\x18"),
565	                0x19 => this.builder.append(.latin1, "\\x19"),
