34	pub fn parse(comptime encoding: Encoding, allocator: std.mem.Allocator, input: []const encoding.unit()) Parser(encoding).ParseResult {
35	    var parser: Parser(encoding) = .init(allocator, input);
36	
37	    const stream = parser.parse() catch |err| {
38	        return .fail(err, &parser);
39	    };
40	
41	    return .success(stream, &parser);
42	}
