44	pub fn print(comptime encoding: Encoding, allocator: std.mem.Allocator, stream: Parser(encoding).Stream, writer: anytype) std.Io.Writer.Error!void {
45	    var printer: Parser(encoding).Printer(@TypeOf(writer)) = .{
46	        .input = stream.input,
47	        .stream = stream,
48	        .indent = .none,
49	        .writer = writer,
50	        .allocator = allocator,
51	    };
52	
53	    try printer.print();
54	}
