21	pub fn renderToHTML(
22	    globalThis: *jsc.JSGlobalObject,
23	    callframe: *jsc.CallFrame,
24	) bun.JSError!jsc.JSValue {
25	    const input_value, const opts_value = callframe.argumentsAsArray(2);
26	
27	    if (input_value.isEmptyOrUndefinedOrNull()) {
28	        return globalThis.throwInvalidArguments("Expected a string or buffer to render", .{});
29	    }
30	
31	    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
32	    defer arena.deinit();
33	
34	    const buffer = try jsc.Node.StringOrBuffer.fromJS(globalThis, arena.allocator(), input_value) orelse {
35	        return globalThis.throwInvalidArguments("Expected a string or buffer to render", .{});
36	    };
37	
38	    const input = buffer.slice();
39	
40	    const options = try parseOptions(globalThis, opts_value);
41	
42	    const result = md.renderToHtmlWithOptions(input, arena.allocator(), options) catch {
43	        return globalThis.throwOutOfMemory();
44	    };
45	
46	    return bun.String.createUTF8ForJS(globalThis, result);
47	}
