49	fn parseOptions(globalThis: *jsc.JSGlobalObject, opts_value: JSValue) bun.JSError!md.Options {
50	    var options: md.Options = .{};
51	    if (opts_value.isObject()) {
52	        // Handle compound autolinks: true | { url, www, email }
53	        if (try opts_value.get(globalThis, "autolinks")) |autolinks_val| {
54	            if (autolinks_val.isBoolean()) {
55	                if (autolinks_val.toBoolean()) {
56	                    options.permissive_autolinks = true;
57	                }
58	            } else if (autolinks_val.isObject()) {
59	                if (try autolinks_val.getBooleanLoose(globalThis, "url")) |v| options.permissive_url_autolinks = v;
60	                if (try autolinks_val.getBooleanLoose(globalThis, "www")) |v| options.permissive_www_autolinks = v;
61	                if (try autolinks_val.getBooleanLoose(globalThis, "email")) |v| options.permissive_email_autolinks = v;
62	            }
63	        }
64	
65	        // Handle compound headings: true | { ids, autolink }
66	        if (try opts_value.get(globalThis, "headings")) |headings_val| {
67	            if (headings_val.isBoolean()) {
68	                if (headings_val.toBoolean()) {
69	                    options.heading_ids = true;
70	                    options.autolink_headings = true;
71	                }
72	            } else if (headings_val.isObject()) {
73	                if (try headings_val.getBooleanLoose(globalThis, "ids")) |v| options.heading_ids = v;
74	                if (try headings_val.getBooleanLoose(globalThis, "autolink")) |v| options.autolink_headings = v;
75	            }
76	        }
77	
78	        // Handle remaining boolean options (autolinks/headings are only settable via compound options above)
79	        inline for (@typeInfo(md.Options).@"struct".fields) |field| {
80	            comptime if (field.type != bool or
81	                std.mem.eql(u8, field.name, "permissive_autolinks") or
