// Self-contained INI parser.  Produces an ast.Expr representing the
// parsed document as a nested-object tree.
//
// Format supported:
//   ; comment         (semicolon comment)
//   # comment         (hash comment)
//   [section]         (simple section header)
//   [a.b.c]           (dot-nested section header)
//   key = value       (key/value pair; spaces around '=' are optional)
//
// Value coercion applied to the trimmed right-hand side:
//   "true" | "yes" | "on"   → E.Boolean true
//   "false" | "no" | "off"  → E.Boolean false
//   "null" | "~"            → E.Null
//   integer literal         → E.Number
//   float literal           → E.Number
//   everything else         → E.String (slice into source text)
//
// NOTE: The caller must enter an ASTMemoryAllocator scope before calling parse().

pub const INI = struct {
    /// Parse an INI document and return a root `ast.Expr` of kind `e_object`.
    ///
    /// Prerequisites:
    ///   - An `ASTMemoryAllocator` must be active on the current thread
    ///     (Expr.init() uses it internally).
    ///   - `allocator` is an arena whose lifetime covers all use of the returned
    ///     expression.
    pub fn parse(source: *const logger.Source, allocator: std.mem.Allocator) !Expr {
        const text = source.contents;

        // Root object holds global (sectionless) key=value pairs.
        var root: E.Object = .{};
        // Points to the E.Object that currently receives new key=value pairs.
        var current: *E.Object = &root;

        var pos: usize = 0;

        while (pos < text.len) {
            // Skip leading horizontal whitespace.
            while (pos < text.len and (text[pos] == ' ' or text[pos] == '\t')) : (pos += 1) {}

            if (pos >= text.len) break;

            switch (text[pos]) {
                // ---- blank / empty line -----------------------------------------------
                '\r', '\n' => {
                    if (text[pos] == '\r' and pos + 1 < text.len and text[pos + 1] == '\n')
                        pos += 1;
                    pos += 1;
                },

                // ---- comment line -----------------------------------------------------
                ';', '#' => {
                    skipToEndOfLine(text, &pos);
                },

                // ---- section header [name] or [a.b.c] --------------------------------
                '[' => {
                    pos += 1; // skip '['
                    const name_start = pos;
                    while (pos < text.len and text[pos] != ']' and
                        text[pos] != '\n' and text[pos] != '\r') : (pos += 1)
                    {}
                    const raw_name = text[name_start..pos];
                    if (pos < text.len and text[pos] == ']') pos += 1; // skip ']'
                    skipToEndOfLine(text, &pos);

                    const section_name = std.mem.trim(u8, raw_name, " \t");
                    if (section_name.len == 0) {
                        current = &root;
                    } else {
                        current = try navigateSection(&root, section_name, allocator);
                    }
                },

                // ---- key = value pair ------------------------------------------------
                else => {
                    const key_start = pos;
                    while (pos < text.len and text[pos] != '=' and
                        text[pos] != '\n' and text[pos] != '\r') : (pos += 1)
                    {}

                    if (pos >= text.len or text[pos] != '=') {
                        // No '=' on this line – skip.
                        skipToEndOfLine(text, &pos);
                        continue;
                    }

                    const raw_key = text[key_start..pos];
                    pos += 1; // skip '='
                    const val_start = pos;
                    while (pos < text.len and text[pos] != '\n' and text[pos] != '\r') : (pos += 1) {}
                    const raw_val = stripInlineComment(std.mem.trim(u8, text[val_start..pos], " \t"));

                    const key = std.mem.trim(u8, raw_key, " \t");
                    if (key.len == 0) continue;

                    const key_copy = try allocator.dupe(u8, key);
                    const val_expr = coerce(raw_val);
                    const key_expr = Expr.init(E.String, E.String{ .data = key_copy }, logger.Loc.Empty);

                    // Overwrite if the key already exists in the current section.
                    var updated = false;
                    for (current.properties.slice()) |*prop| {
                        if (prop.key) |k| {
                            if (k.data == .e_string and
                                std.mem.eql(u8, k.data.e_string.data, key))
                            {
                                prop.value = val_expr;
                                updated = true;
                                break;
                            }
                        }
                    }
                    if (!updated) {
                        try current.properties.append(allocator, .{
                            .key = key_expr,
                            .value = val_expr,
                        });
                    }
                },
            }
        }

        return Expr.init(E.Object, root, logger.Loc.Empty);
    }

    // ---- helpers ------------------------------------------------------------------

    /// Walk a dot-separated `section_name` (e.g. "foo.bar.baz"), creating nested
    /// E.Object nodes as needed, and return a pointer to the innermost one.
    fn navigateSection(
        root: *E.Object,
        section_name: []const u8,
        allocator: std.mem.Allocator,
    ) !*E.Object {
        var obj: *E.Object = root;
        var rest = section_name;

        while (rest.len > 0) {
            const dot = std.mem.indexOfScalar(u8, rest, '.');
            const part = if (dot) |d| rest[0..d] else rest;
            rest = if (dot) |d| rest[d + 1 ..] else "";

            const name = std.mem.trim(u8, part, " \t");
            if (name.len == 0) continue;

            // Look for an existing object-valued property with this name.
            var found: ?*E.Object = null;
            for (obj.properties.slice()) |*prop| {
                if (prop.key) |k| {
                    if (k.data == .e_string and
                        std.mem.eql(u8, k.data.e_string.data, name))
                    {
                        if (prop.value) |v| {
                            if (v.data == .e_object) {
                                found = v.data.e_object;
                            }
                        }
                        break;
                    }
                }
            }

            if (found) |f| {
                obj = f;
            } else {
                // Create a new empty section object and attach it.
                const name_copy = try allocator.dupe(u8, name);
                const new_expr = Expr.init(E.Object, E.Object{}, logger.Loc.Empty);
                try obj.properties.append(allocator, .{
                    .key = Expr.init(E.String, E.String{ .data = name_copy }, logger.Loc.Empty),
                    .value = new_expr,
                });
                // `e_object` is stored as a *E.Object (heap-allocated by Data.Store),
                // so the pointer is stable across BabyList reallocations.
                obj = obj.properties.slice()[obj.properties.len - 1].value.?.data.e_object;
            }
        }

        return obj;
    }

    /// Strip a trailing inline comment (` ; text` or ` # text`) from a value.
    /// Only strips when the comment character is immediately preceded by a space,
    /// to avoid breaking values like file paths that contain '#'.
    fn stripInlineComment(val: []const u8) []const u8 {
        var i: usize = 0;
        while (i < val.len) : (i += 1) {
            if ((val[i] == ';' or val[i] == '#') and i > 0 and val[i - 1] == ' ') {
                return std.mem.trimRight(u8, val[0..i], " \t");
            }
        }
        return val;
    }

    /// Advance `pos` past the end of the current line (consuming the newline too).
    fn skipToEndOfLine(text: []const u8, pos: *usize) void {
        while (pos.* < text.len and text[pos.*] != '\n' and text[pos.*] != '\r') : (pos.* += 1) {}
        if (pos.* < text.len) {
            if (text[pos.*] == '\r' and pos.* + 1 < text.len and text[pos.* + 1] == '\n')
                pos.* += 1;
            pos.* += 1;
        }
    }

    /// Convert a raw INI value string to the most specific ast.Expr type.
    fn coerce(raw: []const u8) Expr {
        if (std.mem.eql(u8, raw, "true") or
            std.mem.eql(u8, raw, "yes") or
            std.mem.eql(u8, raw, "on"))
        {
            return Expr.init(E.Boolean, E.Boolean{ .value = true }, logger.Loc.Empty);
        }
        if (std.mem.eql(u8, raw, "false") or
            std.mem.eql(u8, raw, "no") or
            std.mem.eql(u8, raw, "off"))
        {
            return Expr.init(E.Boolean, E.Boolean{ .value = false }, logger.Loc.Empty);
        }
        if (std.mem.eql(u8, raw, "null") or std.mem.eql(u8, raw, "~")) {
            return Expr.init(E.Null, E.Null{}, logger.Loc.Empty);
        }
        // Integer
        if (std.fmt.parseInt(i64, raw, 10)) |n| {
            return Expr.init(E.Number, E.Number{ .value = @as(f64, @floatFromInt(n)) }, logger.Loc.Empty);
        } else |_| {}
        // Float
        if (std.fmt.parseFloat(f64, raw)) |f| {
            return Expr.init(E.Number, E.Number{ .value = f }, logger.Loc.Empty);
        } else |_| {}
        // String (slice into the source – valid while the source buffer is alive)
        return Expr.init(E.String, E.String{ .data = raw }, logger.Loc.Empty);
    }
};

