pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    var scope: bun.AllocationScope = .init(bun.default_allocator);
    defer scope.deinit();

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    var s: Stringifier = .{
        .builder = &builder,
        .allocator = scope.allocator(),
        .stack_check = .init(),
        .has_global_content = false,
    };

    try s.writeRoot(global, value);

    return builder.toString(global);
}

const Stringifier = struct {
    builder: *wtf.StringBuilder,
    allocator: std.mem.Allocator,
    stack_check: bun.StackCheck,
    /// True once we have emitted at least one key=value or section line at the
    /// root level – used to insert a blank line before the first section.
