    const StringifyError = bun.JSError || bun.StackOverflow;

    /// Entry point: write the root object.
    pub fn writeRoot(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) return error.StackOverflow;

        const unwrapped = try value.unwrapBoxedPrimitive(global);

        // For non-objects, emit a bare scalar (unusual for INI but not invalid).
        if (!unwrapped.isObject() or unwrapped.isArray()) {
            try this.appendScalar(global, unwrapped);
            return;
        }

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
            try .init(global, try unwrapped.toObject(global));
        defer iter.deinit();

        // --- Phase 1: emit root-level scalars (non-object values) ------------------
        while (try iter.next()) |prop_name| {
            const v = iter.value;
            if (v.isUndefined() or v.isSymbol() or v.isFunction()) continue;
            const v_unwrapped = try v.unwrapBoxedPrimitive(global);
            if (v_unwrapped.isObject() and !v_unwrapped.isArray()) continue; // handled in phase 2

            this.appendKeyName(prop_name);
            this.builder.append(.latin1, " = ");
            try this.appendScalar(global, v_unwrapped);
            this.builder.append(.lchar, '\n');
            this.has_global_content = true;
        }

        // Re-iterate for phase 2 (object-valued properties → sections).
        iter.reset();

        // --- Phase 2: emit sections for object-valued properties ------------------
        while (try iter.next()) |prop_name| {
            const v = iter.value;
            if (v.isUndefined() or v.isSymbol() or v.isFunction()) continue;
            const v_unwrapped = try v.unwrapBoxedPrimitive(global);
            if (!v_unwrapped.isObject() or v_unwrapped.isArray()) continue;

            var path_buf = std.ArrayList(u8).init(this.allocator);
            defer path_buf.deinit();
            try path_buf.appendSlice(prop_name.byteSlice());
            try this.writeSection(global, v_unwrapped, path_buf.items);
        }
    }

    /// Recursively emit a `[path]` section and its contents.
    fn writeSection(
        this: *Stringifier,
        global: *jsc.JSGlobalObject,
        value: JSValue,
        path: []const u8,
    ) StringifyError!void {
        if (!this.stack_check.isSafeToRecurse()) return error.StackOverflow;

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) =
            try .init(global, try value.toObject(global));
        defer iter.deinit();

        // Emit blank line separator + section header.
        if (this.has_global_content) {
            this.builder.append(.lchar, '\n');
        }
        this.builder.append(.lchar, '[');
        this.builder.append(.latin1, path);
        this.builder.append(.latin1, "]\n");
        this.has_global_content = true;

        // --- Phase 1: scalar properties ---
        while (try iter.next()) |prop_name| {
            const v = iter.value;
            if (v.isUndefined() or v.isSymbol() or v.isFunction()) continue;
            const v_unwrapped = try v.unwrapBoxedPrimitive(global);
            if (v_unwrapped.isObject() and !v_unwrapped.isArray()) continue;

            this.appendKeyName(prop_name);
            this.builder.append(.latin1, " = ");
            try this.appendScalar(global, v_unwrapped);
            this.builder.append(.lchar, '\n');
        }

        iter.reset();

        // --- Phase 2: nested object properties (sub-sections) ---
        while (try iter.next()) |prop_name| {
            const v = iter.value;
            if (v.isUndefined() or v.isSymbol() or v.isFunction()) continue;
            const v_unwrapped = try v.unwrapBoxedPrimitive(global);
            if (!v_unwrapped.isObject() or v_unwrapped.isArray()) continue;

            // Build "parent.child" path.
            var child_path = std.ArrayList(u8).init(this.allocator);
            defer child_path.deinit();
            try child_path.appendSlice(path);
            try child_path.append('.');
            try child_path.appendSlice(prop_name.byteSlice());

            try this.writeSection(global, v_unwrapped, child_path.items);
        }
    }

    /// Append a scalar value to the builder.
    fn appendScalar(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        if (value.isNull()) {
            this.builder.append(.latin1, "null");
            return;
        }
        if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
            return;
        }
        if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
            return;
        }
        if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
            return;
        }
        // Arrays and other objects – emit as JSON string for lack of a better option.
        if (value.isArray()) {
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
            return;
        }
    }

    /// Append a property-name string (bun.String) to the builder.
    fn appendKeyName(this: *Stringifier, name: bun.String) void {
        this.builder.append(.string, name);
    }
};

