describe("Bun.INI", () => {
  // ---------------------------------------------------------------------------
  // Existence
  // ---------------------------------------------------------------------------
  test("Bun.INI exists with parse and stringify", () => {
    expect(typeof Bun.INI).toBe("object");
    expect(typeof Bun.INI.parse).toBe("function");
    expect(typeof Bun.INI.stringify).toBe("function");
  });

  // ---------------------------------------------------------------------------
  // parse – basic key=value (no section)
  // ---------------------------------------------------------------------------
  describe("parse", () => {
    test("empty string returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("global key=value pairs", () => {
      const result = Bun.INI.parse("name = Alice\nage = 30\n");
      expect(result).toEqual({ name: "Alice", age: 30 });
    });

    test("whitespace around = is trimmed", () => {
      const result = Bun.INI.parse("key=value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("leading/trailing spaces in key and value are trimmed", () => {
      const result = Bun.INI.parse("  key  =  value  \n");
      expect(result).toEqual({ key: "value" });
    });

    // ---- sections -----------------------------------------------------------
    test("single section", () => {
      const input = `
[database]
host = localhost
port = 5432
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        database: { host: "localhost", port: 5432 },
      });
    });

    test("global keys + section", () => {
      const input = `
name = MyApp
version = 1

[server]
host = 0.0.0.0
port = 8080
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        name: "MyApp",
        version: 1,
        server: { host: "0.0.0.0", port: 8080 },
      });
    });

    test("multiple sections", () => {
      const input = `
[foo]
a = 1

[bar]
b = 2
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({ foo: { a: 1 }, bar: { b: 2 } });
    });

    // ---- dot-nested sections ------------------------------------------------
    test("dot-nested section creates nested object", () => {
      const input = `
[database.credentials]
user = admin
password = secret
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        database: {
          credentials: { user: "admin", password: "secret" },
        },
      });
    });

    test("sibling dot sections share parent", () => {
      const input = `
[app.server]
port = 3000

[app.db]
host = localhost
`;
      const result = Bun.INI.parse(input);
      expect(result).toEqual({
        app: {
          server: { port: 3000 },
          db: { host: "localhost" },
        },
      });
    });

    // ---- comments -----------------------------------------------------------
    test("semicolon comment lines are ignored", () => {
      const result = Bun.INI.parse("; comment\nkey = value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("hash comment lines are ignored", () => {
      const result = Bun.INI.parse("# comment\nkey = value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("inline comment after space is stripped", () => {
      const result = Bun.INI.parse("key = value ; comment\n");
      expect(result).toEqual({ key: "value" });
    });

    test("hash or semicolon in value without preceding space is kept", () => {
      // e.g. a URL fragment – should not be treated as a comment
      const result = Bun.INI.parse("url = http://example.com/path#anchor\n");
      expect((result as any).url).toBe("http://example.com/path#anchor");
    });

    // ---- value coercion -----------------------------------------------------
    test("true/yes/on coerce to boolean true", () => {
      const r = Bun.INI.parse("a = true\nb = yes\nc = on\n") as any;
      expect(r.a).toBe(true);
      expect(r.b).toBe(true);
      expect(r.c).toBe(true);
    });

    test("false/no/off coerce to boolean false", () => {
      const r = Bun.INI.parse("a = false\nb = no\nc = off\n") as any;
      expect(r.a).toBe(false);
      expect(r.b).toBe(false);
      expect(r.c).toBe(false);
    });

    test("null and ~ coerce to null", () => {
      const r = Bun.INI.parse("a = null\nb = ~\n") as any;
      expect(r.a).toBeNull();
      expect(r.b).toBeNull();
    });

    test("integer values become numbers", () => {
      const r = Bun.INI.parse("port = 8080\nneg = -1\n") as any;
      expect(r.port).toBe(8080);
      expect(r.neg).toBe(-1);
    });

    test("float values become numbers", () => {
      const r = Bun.INI.parse("ratio = 0.5\n") as any;
      expect(r.ratio).toBeCloseTo(0.5);
    });

    test("string values stay as strings", () => {
      const r = Bun.INI.parse("name = hello world\n") as any;
      expect(r.name).toBe("hello world");
    });

    // ---- duplicate keys -----------------------------------------------------
    test("duplicate keys: last value wins", () => {
      const r = Bun.INI.parse("key = first\nkey = second\n") as any;
      expect(r.key).toBe("second");
    });

    // ---- edge cases ---------------------------------------------------------
    test("lines without = are skipped", () => {
      const r = Bun.INI.parse("not_a_pair\nkey = value\n");
      expect(r).toEqual({ key: "value" });
    });

    test("blank lines are ignored", () => {
      const r = Bun.INI.parse("\n\nkey = value\n\n");
      expect(r).toEqual({ key: "value" });
    });

    test("throws on non-string input", () => {
      // @ts-expect-error
      expect(() => Bun.INI.parse(null)).toThrow();
    });
  });

  // ---------------------------------------------------------------------------
  // stringify
  // ---------------------------------------------------------------------------
  describe("stringify", () => {
    test("empty object produces empty string", () => {
      expect(Bun.INI.stringify({})).toBe("");
    });

    test("scalar properties are emitted as key = value", () => {
      const out = Bun.INI.stringify({ name: "Alice", port: 8080 });
      expect(out).toContain("name = Alice");
      expect(out).toContain("port = 8080");
    });

    test("boolean values are emitted as true/false", () => {
      const out = Bun.INI.stringify({ enabled: true, debug: false });
      expect(out).toContain("enabled = true");
      expect(out).toContain("debug = false");
    });

    test("null values are emitted as null", () => {
      const out = Bun.INI.stringify({ val: null });
      expect(out).toContain("val = null");
    });

    test("object values produce [section] headers", () => {
      const out = Bun.INI.stringify({ database: { host: "localhost" } });
      expect(out).toContain("[database]");
      expect(out).toContain("host = localhost");
    });

    test("nested objects produce dot-notation section headers", () => {
      const out = Bun.INI.stringify({
        app: { server: { port: 3000 } },
      });
      expect(out).toContain("[app.server]");
      expect(out).toContain("port = 3000");
    });

    test("global scalars appear before sections", () => {
      const out = Bun.INI.stringify({ name: "Alice", db: { host: "localhost" } });
      const nameIdx = out.indexOf("name = Alice");
      const sectionIdx = out.indexOf("[db]");
      expect(nameIdx).toBeGreaterThanOrEqual(0);
      expect(sectionIdx).toBeGreaterThanOrEqual(0);
      expect(nameIdx).toBeLessThan(sectionIdx);
    });

    // ---- round-trip ---------------------------------------------------------
    test("parse(stringify(obj)) round-trips simple objects", () => {
      const original = {
        name: "MyApp",
        port: 9000,
        enabled: true,
        database: {
          host: "db.example.com",
          port: 5432,
          ssl: false,
        },
      };
      const iniString = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(iniString) as typeof original;
      expect(parsed.name).toBe("MyApp");
      expect(parsed.port).toBe(9000);
      expect(parsed.enabled).toBe(true);
      expect(parsed.database.host).toBe("db.example.com");
      expect(parsed.database.port).toBe(5432);
      expect(parsed.database.ssl).toBe(false);
    });

    test("parse(stringify(obj)) round-trips nested sections", () => {
      const original = {
        app: {
          server: { port: 3000 },
          db: { host: "localhost" },
        },
      };
      const iniString = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(iniString) as typeof original;
      expect(parsed.app.server.port).toBe(3000);
      expect(parsed.app.db.host).toBe("localhost");
    });
  });
});

