1	// Self-contained INI parser.  Produces an ast.Expr representing the
2	// parsed document as a nested-object tree.
3	//
4	// Format supported:
5	//   ; comment         (semicolon comment)
6	//   # comment         (hash comment)
7	//   [section]         (simple section header)
8	//   [a.b.c]           (dot-nested section header)
9	//   key = value       (key/value pair; spaces around '=' are optional)
10	//
11	// Value coercion applied to the trimmed right-hand side:
12	//   "true" | "yes" | "on"   → E.Boolean true
13	//   "false" | "no" | "off"  → E.Boolean false
14	//   "null" | "~"            → E.Null
15	//   integer literal         → E.Number
16	//   float literal           → E.Number
17	//   everything else         → E.String (slice into source text)
18	//
19	// NOTE: The caller must enter an ASTMemoryAllocator scope before calling parse().
20	
21	pub const INI = struct {
22	    /// Parse an INI document and return a root `ast.Expr` of kind `e_object`.
23	    ///
24	    /// Prerequisites:
25	    ///   - An `ASTMemoryAllocator` must be active on the current thread
26	    ///     (Expr.init() uses it internally).
27	    ///   - `allocator` is an arena whose lifetime covers all use of the returned
28	    ///     expression.
29	    pub fn parse(source: *const logger.Source, allocator: std.mem.Allocator) !Expr {
30	        const text = source.contents;
31	
32	        // Root object holds global (sectionless) key=value pairs.
33	        var root: E.Object = .{};
34	        // Points to the E.Object that currently receives new key=value pairs.
35	        var current: *E.Object = &root;
36	
37	        var pos: usize = 0;
38	
39	        while (pos < text.len) {
40	            // Skip leading horizontal whitespace.
41	            while (pos < text.len and (text[pos] == ' ' or text[pos] == '\t')) : (pos += 1) {}
42	
43	            if (pos >= text.len) break;
44	
45	            switch (text[pos]) {
46	                // ---- blank / empty line -----------------------------------------------
47	                '\r', '\n' => {
48	                    if (text[pos] == '\r' and pos + 1 < text.len and text[pos + 1] == '\n')
49	                        pos += 1;
50	                    pos += 1;
51	                },
52	
53	                // ---- comment line -----------------------------------------------------
54	                ';', '#' => {
55	                    skipToEndOfLine(text, &pos);
56	                },
57	
58	                // ---- section header [name] or [a.b.c] --------------------------------
59	                '[' => {
60	                    pos += 1; // skip '['
61	                    const name_start = pos;
62	                    while (pos < text.len and text[pos] != ']' and
63	                        text[pos] != '\n' and text[pos] != '\r') : (pos += 1)
64	                    {}
65	                    const raw_name = text[name_start..pos];
66	                    if (pos < text.len and text[pos] == ']') pos += 1; // skip ']'
67	                    skipToEndOfLine(text, &pos);
68	
69	                    const section_name = std.mem.trim(u8, raw_name, " \t");
70	                    if (section_name.len == 0) {
71	                        current = &root;
72	                    } else {
73	                        current = try navigateSection(&root, section_name, allocator);
74	                    }
75	                },
76	
77	                // ---- key = value pair ------------------------------------------------
78	                else => {
79	                    const key_start = pos;
80	                    while (pos < text.len and text[pos] != '=' and
81	                        text[pos] != '\n' and text[pos] != '\r') : (pos += 1)
82	                    {}
83	
84	                    if (pos >= text.len or text[pos] != '=') {
85	                        // No '=' on this line – skip.
86	                        skipToEndOfLine(text, &pos);
87	                        continue;
88	                    }
89	
90	                    const raw_key = text[key_start..pos];
91	                    pos += 1; // skip '='
